cd /tmp/sv-20a24fb7e7b345aca5ffb776f60801be/moderate-msbuild-properties && dotnet list Platform.sln package --format json 2>/dev/null | python3 -c "
import json,sys
data=json.load(sys.stdin)
for p in data['projects']:
    name=p['path'].split('/')[-1]
    for fw in p['frameworks']:
        for pkg in fw['topLevelPackages']:
            print(f'{name}: {pkg[\"id\"]} {pkg[\"requestedVersion\"]} -> {pkg[\"resolvedVersion\"]}')
"

